/** 学派（可选，用于筛选与展示） */
export const SPELL_SCHOOLS = [
  '防护',
  '咒法',
  '预言',
  '惑控',
  '塑能',
  '幻术',
  '死灵',
  '变化',
  '灵能',
]

const CUSTOM_SPELLS_KEY = 'dnd_custom_spells'
let customSpellsRemoteCache = null

export async function loadCustomSpellsFromSupabase() {
  if (!isSupabaseEnabled()) return
  try {
    customSpellsRemoteCache = await teamData.fetchCustomLibrary('custom_spells')
  } catch {
    customSpellsRemoteCache = []
  }
}

/** 自定义法术 */
export function getCustomSpells() {
  if (isSupabaseEnabled()) {
    return Array.isArray(customSpellsRemoteCache) ? [...customSpellsRemoteCache] : []
  }
  try {
    const raw = localStorage.getItem(CUSTOM_SPELLS_KEY)
    const list = raw ? JSON.parse(raw) : []
    return Array.isArray(list) ? list : []
  } catch {
    return []
  }
}

function saveCustomSpellsLocal(list) {
  try {
    localStorage.setItem(CUSTOM_SPELLS_KEY, JSON.stringify(list))
  } catch (_) {}
}

function persistCustomSpells(list) {
  if (isSupabaseEnabled()) {
    customSpellsRemoteCache = [...list]
    return teamData.saveCustomLibrary('custom_spells', customSpellsRemoteCache)
  }
  saveCustomSpellsLocal(list)
  return Promise.resolve()
}

/** 内置 + 自定义合并列表（法术大全、角色卡统一使用此列表） */
export function getMergedSpells() {
  return [...SPELLS, ...getCustomSpells()]
}

/** 新增自定义法术；返回新项（含 id） */
export function addCustomSpell(spell) {
  const list = getCustomSpells()
  const id = (spell.id && String(spell.id).trim()) || 'custom_spell_' + Date.now()
  const newSpell = {
    id,
    name: spell.name?.trim() || '未命名',
    level: spell.level != null ? Math.max(0, Math.min(9, parseInt(spell.level, 10) || 0)) : 0,
    school: spell.school?.trim() || '',
    source: Array.isArray(spell.source) ? spell.source : (spell.source ? [spell.source] : []),
    castingTime: spell.castingTime?.trim() || '',
    range: spell.range?.trim() || '',
    components: spell.components?.trim() || '',
    duration: spell.duration?.trim() || '',
    description: spell.description?.trim() || '',
    ritual: !!spell.ritual,
  }
  list.push(newSpell)
  const p = persistCustomSpells(list)
  if (p && typeof p.then === 'function') return p.then(() => newSpell)
  return newSpell
}

/** 更新自定义法术（仅自定义项可更新） */
export function updateCustomSpell(id, patch) {
  const list = getCustomSpells()
  const idx = list.findIndex((s) => s.id === id)
  if (idx === -1) return null
  list[idx] = { ...list[idx], ...patch }
  const pr = persistCustomSpells(list)
  if (pr && typeof pr.then === 'function') return pr.then(() => list[idx])
  return list[idx]
}

/** 删除自定义法术 */
export function removeCustomSpell(id) {
  const list = getCustomSpells().filter((s) => s.id !== id)
  const pr = persistCustomSpells(list)
  if (pr && typeof pr.then === 'function') return pr.then(() => true)
  return Promise.resolve(true)
}

export function getSpellById(id) {
  const built = SPELLS.find((s) => s.id === id)
  if (built) return { ...built }
  const custom = getCustomSpells().find((s) => s.id === id)
  return custom ? { ...custom } : null
}

/** 按环阶筛选，level 0 为戏法 */
export function getSpellsByLevel(level) {
  return getMergedSpells().filter((s) => s.level === level)
}

/** 按职业法表筛选（source 数组包含该职业名即入选） */
export function getSpellsByClass(className) {
  if (!className) return []
  const SPELL_CLASS_ALIASES = {
    圣骑士: '圣武士',
    邪术师: '魔契师',
    魂灵术士: '魂灵学者',
    雷鸟法师: '蓝御法师',
  }
  const candidates = new Set([className])
  const forward = SPELL_CLASS_ALIASES[className]
  if (forward) candidates.add(forward)
  Object.entries(SPELL_CLASS_ALIASES).forEach(([k, v]) => {
    if (v === className) candidates.add(k)
  })
  return getMergedSpells().filter((s) => {
    const src = Array.isArray(s.source) ? s.source : []
    return [...candidates].some((c) => src.includes(c))
  })
}

/** 按学派筛选 */
export function getSpellsBySchool(school) {
  if (!school) return getMergedSpells()
  return getMergedSpells().filter((s) => s.school === school)
}

/** 仅仪式法术 */
export function getRitualSpells() {
  return getMergedSpells().filter((s) => s.ritual === true)
}

/** 关键词搜索（名称、描述），在合并列表上搜索 */
export function searchSpells(query) {
  const all = getMergedSpells()
  if (!query?.trim()) return all
  const q = query.trim().toLowerCase()
  return all.filter(
    (s) =>
      (s.name && s.name.toLowerCase().includes(q)) ||
      (s.description && s.description.toLowerCase().includes(q))
  )
}

/** 按环阶分组的法术，用于法术大全页分栏展示 */
export function getSpellsByLevelGrouped() {
  const byLevel = {}
  for (let i = 0; i <= 9; i++) byLevel[i] = []
  getMergedSpells().forEach((s) => {
    const lv = s.level != null ? s.level : 0
    if (byLevel[lv]) byLevel[lv].push(s)
  })
  return byLevel
}
